params.description:
JSON mapping with stakeholder data. Example: {
  "campaign_context": "Phase III Trial ABC-123 Data Package",
  "sftp_address": "sftp://files.example.com/submissions",
  "stakeholders": [
    {
      "name": "Acme CRO",
      "email": "data@acme.com",
      "documents": ["Protocol Amendment v2", "Safety Report Q1"],
      "deadline": "2026-06-15",
      "requirements": "PDF format, signed by principal investigator"
    }
  ]
}

script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const values = JSON.parse(input.mapping);

const token = process.env.GITHUB_TOKEN;
const headers = token ? { Authorization: `token ${token}` } : {};
const res = await fetch(
  'https://raw.githubusercontent.com/Appsilon/mediforce-submission-readiness/refs/heads/main/email-template.md',
  { headers }
);
if (!res.ok) throw new Error(`Template fetch failed: ${res.status}`);

let md = await res.text();

for (const [key, val] of Object.entries(values)) {
  md = md.replaceAll(`{${key}}`, String(val));
}

function inlineFmt(text) {
  return text
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*([^*]+)\*/g, '<em>$1</em>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
}

function renderTable(tableLines) {
  const rows = tableLines.filter(l => !/^[\|\s:\-]+$/.test(l.trim()));
  let t = '<table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;margin:12px 0">\n';
  for (const row of rows) {
    const cells = row.split('|').slice(1, -1);
    t += '<tr>' + cells.map(c => `<td style="vertical-align:top;padding:8px;border:1px solid #ccc">${inlineFmt(c.trim())}</td>`).join('') + '</tr>\n';
  }
  return t + '</table>';
}

const lines = md.split('\n');
const blocks = [];
let i = 0;
while (i < lines.length) {
  const line = lines[i];
  if (line.trim().startsWith('|')) {
    const tbl = [];
    while (i < lines.length && lines[i].trim().startsWith('|')) tbl.push(lines[i++]);
    blocks.push(renderTable(tbl));
  } else if (line.trim() === '') {
    i++;
  } else {
    const para = [];
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].trim().startsWith('|')) para.push(lines[i++]);
    blocks.push(`<p style="margin:0 0 1em 0">${inlineFmt(para.map(l => l.trimEnd()).join('<br>'))}</p>`);
  }
}

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;font-size:14px;color:#333;max-width:900px;margin:0 auto;padding:20px;line-height:1.5">\n${blocks.join('\n')}\n</body></html>`;

const stakeholdersEmails =
  (typeof values['stakeholders-emails'] === 'object' && values['stakeholders-emails'] !== null)
    ? values['stakeholders-emails']
    : {};
const recipientEntries = Object.entries(stakeholdersEmails);
const recipientEmails = recipientEntries.map(([, email]) => String(email)).join(',');
const recipientsDisplay = '<ul style="margin:4px 0;padding-left:20px">' +
  recipientEntries.map(([role, email]) => `<li>${role}: ${email}</li>`).join('') +
  '</ul>';

writeFileSync('/output/result.json', JSON.stringify({
  subject: values.subject ?? 'Document Submission Request',
  body: md,
  html,
  presentation: html,
  recipientEmails,
  recipientsDisplay
}));
